sql:
SELECT SUM(operational_cost) AS TotalOperationalCosts
FROM company_financials
WHERE year = 2022;

SELECT DISTINCT business_unit_id 
  FROM company_financials 
  WHERE state_id = (
      SELECT state_id 
      FROM company_financials 
      WHERE employee_count = (
          SELECT MAX(employee_count) 
          FROM company_financials
      )
  );

SELECT users.username, business_units.business_unit_name
FROM users
INNER JOIN business_units ON users.business_unit_id = business_units.business_unit_id;

external_knowledge:
- "Beacons" metaphorically refer to business units guiding their users; 
- The phrase "illuminating the path" metaphorically refers to having users associated with them;
- "No beacon mentioned more than once" indicates the use of the "DISTINCT" keyword to ensure unique business unit names.

sql:
SELECT DISTINCT bu.business_unit_name
FROM business_units bu
INNER JOIN users u ON bu.business_unit_id = u.business_unit_id;

SELECT business_unit_name
FROM business_units
WHERE business_unit_id = 0;
